#!/usr/bin/env node
/**
 * PostCompact Hook: Context Restore & Audit
 *
 * After context compaction completes, injects a systemMessage that forces
 * the model to:
 *   1. Re-state the project's final goal, implementation path, and current issues.
 *   2. Summarize this session's changes and append them to ./docs/CHANGELOG.md.
 *   3. Audit current code for errors or drift from the original goal.
 *
 * Input fields (from Claude Code):
 *   - trigger: "auto" (auto-compact) or "manual" (/compact command)
 *   - compact_summary: the summary generated by the compact operation
 *
 * Matcher values:
 *   - "auto"   → matches auto-compact only
 *   - "manual" → matches manual /compact only
 *   - ""       → matches both
 *
 * Hook ID : PostCompact:context-restore
 */

'use strict';

const fs = require('fs');
const path = require('path');

const MAX_STDIN = 1024 * 1024; // 1MB limit

function tryReadFile(filePath) {
  try {
    return fs.readFileSync(filePath, 'utf8');
  } catch {
    return null;
  }
}

function run(rawInput) {
  let cwd = process.cwd();
  let trigger = 'unknown';
  let compactSummary = '';

  // Extract hook input fields
  try {
    const input = typeof rawInput === 'string' ? JSON.parse(rawInput) : rawInput;
    if (input.cwd) cwd = input.cwd;
    if (input.trigger) trigger = input.trigger;
    if (input.compact_summary) compactSummary = input.compact_summary;
  } catch {
    // Use defaults
  }

  const claudeMd = tryReadFile(path.join(cwd, 'CLAUDE.md'));
  const changelogMd = tryReadFile(path.join(cwd, 'docs', 'CHANGELOG.md'));

  const systemMessage = [
    `[PostCompact] Context was just compacted (trigger: ${trigger}). You MUST now perform the following tasks:`,
    '',
    '## 1. Project State Recall',
    'Read ./CLAUDE.md and answer:',
    '  - What is the final goal of this project?',
    '  - What is the implementation path?',
    '  - What are the current/existing problems?',
    '',
    '## 2. Changelog Update',
    'Summarize ALL changes made in this session and append them to ./docs/CHANGELOG.md.',
    'Use the existing changelog format. Categorize under [Unreleased] with today\'s date.',
    '',
    '## 3. Code Audit',
    'Review the current codebase for:',
    '  - Bugs or errors introduced in this session',
    '  - Code that drifts from the project\'s final goal defined in CLAUDE.md',
    '  - Inconsistencies between the implementation path and actual code state',
    'If issues are found, report them to the user with specific file:line references.',
    '',
    '--- Compact Summary ---',
    compactSummary || '(No compact summary provided)',
    '',
    '--- CLAUDE.md ---',
    claudeMd || '(File not found — please read ./CLAUDE.md directly)',
    '',
    '--- docs/CHANGELOG.md (last 50 lines) ---',
    changelogMd
      ? changelogMd.split('\n').slice(-50).join('\n')
      : '(File not found — please read ./docs/CHANGELOG.md directly)',
    '',
    '--- END ---',
  ].join('\n');

  return JSON.stringify({
    continue: true,
    suppressOutput: false,
    systemMessage,
  });
}

// stdin entry point
if (require.main === module) {
  let data = '';
  process.stdin.setEncoding('utf8');
  process.stdin.on('data', chunk => {
    if (data.length < MAX_STDIN) {
      data += chunk.substring(0, MAX_STDIN - data.length);
    }
  });
  process.stdin.on('end', () => {
    const output = run(data);
    process.stdout.write(output);
  });
}

module.exports = { run };